var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 못하겠어! 못하겠다구!! 전교생이 듣는데 부끄럽게 그걸 어떻게 해!?","JPN":"うう、やっぱりできない！　できないわよ！　全校生徒の前でこんな恥ずかしいことできるわけないでしょ！","ENG":"Bah! I can't do it! I just can't!! How can I say that in front of everybody without getting embarrassed?!","TWN":"唉唷，我不行啦！我做不到！！全校學生都會聽到欸，那麼害羞，我沒辦法啦！"},"stage":{"bg":"SKY","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이상해. 기억은 흐릿하지만…… 무언가 반복되고 있어.","JPN":"おかしい。また<color=#ffd34c>学園祭の前日</color>だ。\\n記憶がはっきりしないけど……確かに繰り返されてる。","ENG":"Something's off. My memory's fuzzy... but I feel like something's repeating.","TWN":"奇怪，雖然記憶有點模糊……但好像一直在重複某件事。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"오늘뿐이 아니야. 어제도…… 분명, 그전에도…….","JPN":"今日だけじゃない。昨日も……きっと、その前も……\\n<color=#ffd34c>学園祭の前日</color>を繰り返しているんだ。","ENG":"It's not just today. Yesterday... and even the day before...","TWN":"不只是今天，昨天也是……還有之前……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"미나야!","JPN":"ミナ！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"여기서 뭘 하고 있어! 다들 널 얼마나 찾았는데!","JPN":"もう！　こんなところで何してるの？　みんな探してたんだよ！","ENG":"Seriously? What are you doing here? Everyone's been looking all over for you!","TWN":"真是的！你在這裡做什麼！大家都在找你！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……역시.","JPN":"やっぱり……","ENG":"...Just as I thought.","TWN":"……果然。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"응? 역시라니? 무슨 말이야?","JPN":"うん？　やっぱりって？　どういう意味なの？","ENG":"Hmm? Just as you thought? What do you mean?","TWN":"嗯？果然什麼？你在說什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니. 별거 아니야, 기다리고 있었어. 셜리.","JPN":"いや、何でもない。待ってたよ、シャーリー。","ENG":"Nothing. I was waiting for you, Shirley.","TWN":"沒事，沒什麼，我正好在等你呢，夏麗。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"다음은 사진부에서 온 건이야. 전시에 관해 문제가 있다고 하는군.","JPN":"次は写真部からだ。展示に関してのトラブルだな","ENG":"Next is from the photography club. They seem to be having a problem regarding their exhibition.","TWN":"接下來是攝影部的訴求，是與展出有關的問題。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전시 일정을 다시 조율해달라고 하는데……","JPN":"展示日程を再度調整してほしいとのことだが……おそらくこちらは……","ENG":"They want us to reschedule the exhibition...","TWN":"他們希望可以調整展出的日期……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 를르슈!","JPN":"待って、ルルーシュ！","ENG":"Hold on, Lelouch!","TWN":"先等一下，魯路修！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이거 사진부에서 잃어버렸다고 했던 사진이잖아?","JPN":"これは！？　これって写真部が無くしたって言ってた写真じゃない？","ENG":"Aren't these the missing photos?!","TWN":"這不是攝影部不見的照片嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 왜 학생회실 창고에 있는 거지?","JPN":"どうして、そんなものが生徒会室の倉庫に……","ENG":"But why would they be in the Student Council storage room?","TWN":"為什麼會在學生會辦公室裡？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"왜 그러지, 미나?","JPN":"どうしたんだ、ミナ？","ENG":"What is it, Mina?","TWN":"怎麼了，米娜？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안, 컨디션이 좀 안좋아서. 보건실에 다녀와도 될까?","JPN":"ごめんなさい。少し具合が悪くて。保健室に行ってもいい？","ENG":"Sorry, I'm not feeling well. Could I be excused and go to the nurse's office?","TWN":"不好意思，我狀況不太好，可以去一趟保健室嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수영부 때도…… 사진부때도…… 누군가가 학원제를 방해하고 있었어.","JPN":"水泳部の時も……写真部の時も……誰かが学園祭の邪魔をしてる。","ENG":"The swim club... and the photography club... Someone's trying to stop the festival.","TWN":"游泳部的事也是……還有攝影部的事……有人要破壞學園祭。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기서 기다리고 있으면, 학원제를 방해하는 범인이 누구인지 알 수 있겠지.","JPN":"ここで待っていれば、\\n学園祭を邪魔している犯人が誰なのか突き止められるはず。","ENG":"If I wait here, I'm sure I can find out who the culprit is.","TWN":"只要在這裡守株待兔，就可以知道破壞學園祭的犯人是誰吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"범인의 정체를 알아낸다면, 전야제가 반복되는 원인에 대해서 알 수 있을 지도 몰라.","JPN":"犯人の正体がわかったら、\\nこの<color=#ffd34c>学園祭の前日</color>が繰り返される原因もわかるかもしれない。","ENG":"Once I do, maybe I can find out why this day keeps repeating itself.","TWN":"只要逮到犯人，或許就可以知道學園祭一直重演的原因。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"예상대로 발소리가 들려. 누군가가 오고있어.","JPN":"足音が聞こえる。読みが当たったみたい。誰か来る……","ENG":"I hear footsteps. Someone's coming.","TWN":"如我所料有聽到腳步聲，有人接近中。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"좋아, 아무도 없군.","JPN":"よし、誰もいないな。","ENG":"Okay. No one's here.","TWN":"很好，都沒人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"그럼, 전시 준비가 시작되기 전에 이걸 여기에…….","JPN":"さて、展示の準備が始まる前にこれをここに……","ENG":"Now, before the preparation starts, I'll put this he–","TWN":"只要在攝影展開始前將東西放在這裡……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신 누구야!","JPN":"あんたは何者！？","ENG":"Who are you?!","TWN":"你是誰！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"우왓!? 이런곳에 왜 사람이 있는거야?","JPN":"うわっ！？　どうして、こんなところに人が？","ENG":"Whoa?! Why is there someone in here?!","TWN":"嚇我一跳！？這裡怎麼會有人？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 손에 들고 있는 건…… 사진부가 전시하기로 한 사진이네.","JPN":"その手に持っているのは……写真部の展示用の写真ね。","ENG":"That thing you're holding... Those are the exhibition photos.","TWN":"你手上拿的……就是攝影部要展出的照片吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"역시 내 생각이 맞았어, 당신 어째서 학원제를 방해하는 거야!?","JPN":"やっぱり予想どおりだった。あんた、なんで学園祭を邪魔するの！？","ENG":"I was right. Hey, why are you trying to stop the festival?!","TWN":"我猜得果然沒錯！你為什麼要破壞學園祭！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"내가 학원제를 방해한다고?","JPN":"私が学園祭を邪魔してるだと？","ENG":"I'm trying to stop the festival?","TWN":"我破壞學園祭？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"무슨 소리야? 나는 그냥 이 사진들을 이곳에…….","JPN":"何の話だ？　私はただ写真をここに……","ENG":"That's nonsense! I'm just here to put these photos–","TWN":"你在胡說什麼？我只是把照片放這裡……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기다려. 일단 사진은 돌려 받아야겠어.","JPN":"待って。写真は返してもらうよ。","ENG":"Hold it. First, I'll need those photos back from you.","TWN":"等等，我要先把照片還回去。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"잠깐! 왜 방해하는 거지? 나는 사진을 반드시 여기다 가져다 놓아야만 한다고!","JPN":"やめろ！　私は写真をここに隠さなきゃいけないんだ！","ENG":"Wait! Why are you bothering me? I have to put these photos here!","TWN":"等等！你幹嘛妨礙我？我必須把照片放在這裡！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"큿, 왜 사진에 집착하는 거야!? 당신이 범인이라는 건 알고있어. 수영장에 기름통을 숨겨 놓은 것도!","JPN":"くっ。どうしてそこまでして写真を隠そうとするの？\\nあんたが犯人だってことはわかっているの。プールに油缶を仕込んだのもね！","ENG":"Kgh, what's your obsession with these photos anyway?! I know you're the perp! And I know you hid the oil barrel near the pool, too!","TWN":"哼，你為什麼這麼執著於這些照片！？\\n我就知道你是犯人，也是你把汽油桶藏在游泳池的吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"뭐? 수영장 같은 건 몰라! 나는 그냥 이곳에 사진을 가져다 놓을 뿐이라고!","JPN":"はあ？　プールなんか知らん。私はただ写真を隠さなきゃいけないんだよ！","ENG":"What?! I know nothing about the pool! I'm just here to put the photos!","TWN":"什麼？我才不知道什麼游泳池！我就只是要把照片放在這裡而已！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이게 대체 무슨 소란이죠?","JPN":"これはいったい何の騒ぎでしょう？","ENG":"What's going on here?","TWN":"怎麼這麼吵？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양? 그리고…… 당신은?","JPN":"ミナさん？　そしてあなたは……？","ENG":"Mina? And... you are?","TWN":"米娜？還有……你是？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……다행히 화학 선생님께서는 크게 다치시지는 않았다고 하네요.","JPN":"……幸い、化学の先生は大きな怪我はなかったようです。","ENG":"...Thankfully, the chemistry teacher wasn't injured that bad.","TWN":"……幸好化學老師沒有大礙。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"넘어질 때 충격으로 왜 창고에 왔었는지는 잊어버리신 모양이지만요.","JPN":"転んだ時の衝撃でなぜ倉庫に来たのかは忘れてしまったようですが。","ENG":"However, he doesn't remember why he was in the storage room due to the shock from when he tripped.","TWN":"但老師跌倒時受到衝擊，導致他似乎忘記來倉庫的原因。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"정말, 아무리 그래도 선생님 얼굴을 잊어버리면 어떡해?","JPN":"でもさ、いくらなんでも先生の顔を忘れるなんてある？","ENG":"But really, how could you forget a teacher's face?","TWN":"你真是的，怎麼可以忘記老師的長相呢？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 하하…… 누가 갑자기 창고로 들어오길래, 나도 모르게 그만.","JPN":"は、はは……急に倉庫に入って来たから、つい……","ENG":"Hah, hah hah... I just saw someone coming in the storage room and acted without thinking.","TWN":"哈哈……因為突然有人進來倉庫，我不自覺就…"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 어쨌든 전시 예정인 사진부의 사진을 찾았잖아? 이걸로 전시를 진행할 수 있겠지?","JPN":"と、とにかく！　展示予定の写真も見つかったんだし、\\nこれで写真部の展示は予定どおり進められるよね？\\t","ENG":"A-anyway, I found the missing photos, didn't I? Now, the exhibition can go on, right?","TWN":"總，總之找到攝影部要展出的照片了，這樣應該就可以順利進行吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"으, 으응. 그런데 미나야. 사진이 없어졌다는 건 어떻게 안 거야?","JPN":"それはそうだけど……でもミナ。写真が消えたなんて、どうして気づいたの？","ENG":"Y-yeah. But Mina, how did you know the photo went missing?","TWN":"嗯嗯，不過米娜，你怎麼會知道照片不見的事？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"사진부에 확인해보니까 자기들 사진이 분실됐다는 사실도 모르고 있던데?","JPN":"写真部に確認したら、自分たちの写真が紛失していたことさえ気づいてなかったわよ？","ENG":"When I asked the photography club, they didn't even know the photos were gone.","TWN":"我問過攝影部的人，他們自己也不知道照片不見了。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"맞아요. 애초에 화학 선생님이 가지고 있던 물건이 사진부의 사진이었다는 걸 어떻게 알고 계셨던 거죠?","JPN":"そうですね。そもそも化学の先生が持っていたものが\\n写真部の写真だということを、どうして知っていたのですか？","ENG":"She's right. And how did you know that the chemistry teacher was holding what were, in fact, the missing photos?","TWN":"對啊，你怎麼知道化學老師手上拿的就是攝影部的照片？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저, 저기, 그건…….","JPN":"あ、あの、それは……","ENG":"W-well, I...","TWN":"那，那是，因為…"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야, 그 반응? 왜 말을 똑바로 못해? 너 우리한테 뭔가 숨기는 거라도 있어?","JPN":"何よ、その反応。ちゃんと理由を言いなさいよ！\\nあんた、私たちに何か隠し事でもしてるの？","ENG":"What can't you just say it? Tell us! Is there something you're keeping from us?","TWN":"你那是什麼反應？為什麼支支吾吾的？你是不是有事情瞞著我們？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 그게 아니라, 그러니까…….","JPN":"いや。そうじゃなくて、えっと……","ENG":"No, it's not that, but...","TWN":"沒有啦，是那個…"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하하, 다들 미안 미안. 말 하는 걸 잊고 있었네.","JPN":"ははっ、みんなすまない。うっかり伝え忘れていたよ。","ENG":"Ha ha, apologies, everyone. I forgot to tell you.","TWN":"哈哈，大家不好意思，我忘記說了。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"를르슈 군?","JPN":"ルルーシュさん？","ENG":"Lelouch?","TWN":"魯路修？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아침에 전시관 쪽 자재 정리를 미나한테 부탁했거든. 미나는 거기서 사진부의 사진을 미리 봤던 것 아닐까?","JPN":"今朝、展示会場の資材整理をミナに頼んだんだ。\\nミナはそこで写真部の件に気づいたんじゃないかな？","ENG":"I asked for Mina's help in organizing the props at the gallery this morning. I assume Mina saw the photos then.","TWN":"我早上有請米娜幫忙整理展覽館的資料，所以米娜才會看過攝影部的照片吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전시관에 있어야 할 사진을 누군가 창고로 가져왔으니, 수상하다고 생각했겠지.","JPN":"展示会場にあるべき写真を何者かが倉庫に持ってきたから、怪しいと思ったんだろう。","ENG":"And since someone brought the photos that were supposed to be in the gallery to the storage room, it caused her to be suspicious.","TWN":"然後看到有人把應該放在展覽館的照片拿到倉庫裡來，她才會覺得奇怪吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"아하, 미나가 학생회 회의에 늦었던 건 그런 이유 때문이었구나.","JPN":"なるほどね、ミナが生徒会の会議に遅れたのは、それが理由だったんだ。","ENG":"A-ha! So that's why Mina was late to this meeting.","TWN":"喔喔～米娜是因為這樣學生會會議才會遲到嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하…… 그, 그래. 를르슈 말이 맞아.","JPN":"あはは……そ、そう。ルルーシュの言うとおり……","ENG":"Ah hah hah... Y-yeah. What Lelouch said.","TWN":"哈哈哈……對，對啊，就是魯路修說的那樣。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으음, 이상하네. 역시 뭔가 수상해.","JPN":"うーん、おかしい。やっぱりなんか怪しいわね。","ENG":"Hmm, something feels off. There's something fishy going on here.","TWN":"嗯，不對，還是怪怪的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼, 화학 선생은 왜 사진을 창고까지 가져온 건데?","JPN":"そもそも化学の先生はどうして写真を倉庫に持ってきたの？","ENG":"Then, why would the chemistry teacher take the photos to the storage room?","TWN":"那化學老師為什麼要把照片拿到倉庫裡來？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건…… 나도 모르겠어.","JPN":"それは私にもわからない。私だって知りたいぐらいなんだから。","ENG":"That... I have no idea.","TWN":"這……我也不清楚。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그보다 나이엘, 뭔가 중요한 걸 잊고 있지 않아?","JPN":"それよりもナイエル。大事な仕事を忘れていないか？","ENG":"Wait, Naielle. Aren't you forgetting something more important?","TWN":"先不說這個，奈爾，你忘記還有一樣更重要的事嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"什麼事？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러고보니, 나이엘 양. 후야제에서 피울 캠프파이어 준비는 어떻게 되어가고 있죠?","JPN":"そうですよ、ナイエルさん。\\nお願いしていた後夜祭のキャンプファイヤーの準備の進捗はいかがですか？","ENG":"Speaking of which, Naielle. How are the preparations for the post-festival party's campfire going?","TWN":"話說回來，奈爾，慶功宴要用的營火預備得怎麼樣？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"에, 에엑……? 잠깐, 올해의 캠프파이어 담당이 나라고?","JPN":"え、ええっ！？　今年のキャンプファイヤー担当が私ですって！？","ENG":"E-eck...? Is that supposed to be my duty?","TWN":"欸欸欸……？今年是我負責升營火喔？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……그럼 각자 맡은 일이 끝난 뒤 캠프파이어 준비를 돕도록 하죠.","JPN":"……それでは、各自担当の仕事が終わったらキャンプファイヤーの準備を手伝うことにしましょう。","ENG":"...Then, after we are all done with our tasks, let's help the two out with the campfire preparations.","TWN":"那就各自忙完交付的任務後，再一起協助準備營火。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양? 아까부터 말씀이 없으시네요. 괜찮으세요?","JPN":"ミナさん？　さっきから静かですね、大丈夫ですか？","ENG":"Mina? You haven't said a word. Are you okay?","TWN":"米娜？你怎麼都不說話？還好嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 미안 나도 모르게 잠깐 딴 생각을 했네.","JPN":"あ、ごめん。ちょっと違うことを考えてた。","ENG":"Oh, sorry. I guess I zoned out again.","TWN":"喔，抱歉，我剛在想別的事。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈, 나는 이제 뭘 하면 될까?","JPN":"ルルーシュ、私は何をすればいいのかな？","ENG":"Lelouch, what should I do now?","TWN":"魯路修，我現在要做什麼？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"으음, 그럼 회장을 따라서 연극부에 같이 가줄 수 있겠어?","JPN":"ふむ、それじゃあ会長と一緒に演劇部のほうに行ってくれないか？","ENG":"Hmm, could you help Yen with the theater club complaint?","TWN":"嗯，那米娜可以和會長一起去協助戲劇部嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 연극부를 도우면 된다는 거지? 알겠어.","JPN":"うん、演劇部のお手伝いね。了解。","ENG":"Sure. The theater club, right? Got it.","TWN":"嗯，協助戲劇部就好嗎？好的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};